import React from 'react';
import p1  from '../assets/images/Property 1=Default.png';
import p2  from '../assets/images/Property 1=Default(1).png';
import p3  from '../assets/images/Property 1=Default(2).png';
import p4  from '../assets/images/Property 1=Default(3).png';
import p5  from '../assets/images/Property 1=Default(4).png';
import p6  from '../assets/images/Property 1=Default(5).png';
import p7  from '../assets/images/Property 1=Default(6).png';
import p8  from '../assets/images/Property 1=Default(7).png';
import p9  from '../assets/images/Property 1=Default(8).png';
import p10 from '../assets/images/Property 1=Default(9).png';
import p11 from '../assets/images/Property 1=Default(10).png';
import p12 from '../assets/images/Property 1=Default(11).png';
import './ProductLists.css';

const newArrivals = [
  { id: 1, img: p1,  name: 'MEN Yarn Fleece F...', cat: 'Winter Wear', price: '61.00', old: '61.00' },
  { id: 2, img: p2,  name: "Men's Winter Leat...",  cat: 'Winter Wear', price: '32.00', old: '29.00' },
  { id: 3, img: p3,  name: "Men's Winter Leat...",  cat: 'Jackets',     price: '50.00', old: '25.00' },
  { id: 4, img: p4,  name: 'Better Basics Fren...', cat: 'Shorts',      price: '20.00', old: '13.00' },
];

const trendings = [
  { id: 1, img: p5,  name: 'Running & Trekki...', cat: 'Sports',     price: '49.00', old: '25.00' },
  { id: 2, img: p6,  name: 'Trekking & Runni...', cat: 'Sports',     price: '78.00', old: '38.00' },
  { id: 3, img: p7,  name: "Women's Party W...", cat: 'Party Wear', price: '94.00', old: '95.00' },
  { id: 4, img: p8,  name: 'Sports Claw Wom...', cat: 'Sports',     price: '54.00', old: '85.00' },
];

const topRated = [
  { id: 1, img: p9,  name: 'Platinum Zircon Cl...', cat: 'Jewellery',  price: '62.00', old: '85.00' },
  { id: 2, img: p10, name: 'Smart Watch Viol...',   cat: 'Watches',    price: '58.00', old: '70.00' },
  { id: 3, img: p11, name: 'Shampoo Condit...',     cat: 'Cosmetics',  price: '20.00', old: '30.00' },
  { id: 4, img: p12, name: 'Rose Gold Peacoc...',   cat: 'Jewellery',  price: '25.00', old: '30.00' },
];

function ProductItem({ item }) {
  return (
    <div className="pl-item">
      <div className="pl-img-wrap">
        <img src={item.img} alt={item.name} className="pl-img" />
      </div>
      <div className="pl-info">
        <p className="pl-name">{item.name}</p>
        <p className="pl-cat">{item.cat}</p>
        <div className="pl-price-row">
          <span className="pl-price">${item.price}</span>
          <span className="pl-old">${item.old}</span>
        </div>
      </div>
    </div>
  );
}

function ProductColumn({ title, items }) {
  return (
    <div className="pl-column">
      <h3 className="pl-col-title">{title}</h3>
      <div className="pl-list">
        {items.map((item) => (
          <ProductItem key={item.id} item={item} />
        ))}
      </div>
    </div>
  );
}

export default function ProductLists() {
  return (
    <section className="pl-section">
      <ProductColumn title="New Arrivals" items={newArrivals} />
      <ProductColumn title="Trendings"    items={trendings}   />
      <ProductColumn title="Top Rated"    items={topRated}    />
    </section>
  );
}
